class FoodRatings {

    private Map<String, Map<String, Integer>> foodRatings;

    public FoodRatings(String[] foods, String[] cuisines, int[] ratings) {
        foodRatings = new HashMap<>();
        for (int i = 0; i < foods.length; i++) {
            String food = foods[i];
            String cuisine = cuisines[i];
            int rating = ratings[i];
            foodRatings.computeIfAbsent(cuisine, k -> new HashMap<>()).put(food, rating);
        }
    }

    public void changeRating(String food, int newRating) {
        for (Map<String, Integer> cuisineRatings : foodRatings.values()) {
            cuisineRatings.put(food, newRating);
        }
    }

    public String highestRated(String cuisine) {
        Map<String, Integer> cuisineRatings = foodRatings.get(cuisine);
        if (cuisineRatings == null) {
            return "";
        }
        String highestRatedFood = "";
        int highestRating = Integer.MIN_VALUE;
        for (String food : cuisineRatings.keySet()) {
            int rating = cuisineRatings.get(food);
            if (rating > highestRating) {
                highestRating = rating;
                highestRatedFood = food;
            } else if (rating == highestRating && food.compareTo(highestRatedFood) < 0) {
                highestRatedFood = food;
            }
        }
        return highestRatedFood;
    }
}
